<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  body{font-family:Arial,sans-serif;margin:20px;background:#f9f9f9;}
  h1{margin-bottom:.5em;}
  form{background:#fff;padding:15px;border-radius:4px;box-shadow:0 2px 4px rgba(0,0,0,.1);max-width:500px;}
  label{display:block;margin-top:10px;font-weight:bold;}
  input[type="number"],input[type="date"],select,input[type="text"]{
    width:100%;padding:8px;border:1px solid #ccc;border-radius:4px;box-sizing:border-box;
  }
  button{margin-top:12px;padding:10px 15px;background:#28a745;color:#fff;border:none;border-radius:4px;cursor:pointer;}
  button:hover{background:#218838;}
  .error{color:red;margin-top:5px;}
  #expenses{margin-top:20px;}
  table{width:100%;border-collapse:collapse;background:#fff;}
  th,td{text-align:left;padding:8px;border-bottom:1px solid #ddd;}
  tr.hidden{display:none;}
  .exp-del{background:#dc3545;color:#fff;border:none;padding:4px 6px;border-radius:3px;cursor:pointer;}
  .summary{margin-top:20px;background:#fff;padding:15px;border-radius:4px;box-shadow:0 2px 4px rgba(0,0,0,.1);}
  .summary div{margin-bottom:5px;}
</style>
</head>
<body>

<h1>Expense Tracker</h1>

<form id="expense-form">
  <label for="amount">Amount ($)</label>
  <input type="number" step="0.01" id="amount" required>

  <label for="category">Category</label>
  <select id="category" required>
    <option value="groceries">Groceries</option>
    <option value="transport">Transport</option>
    <option value="bills">Bills</option>
    <option value="fun">Fun</option>
  </select>

  <label for="date">Date</label>
  <input type="date" id="date" required>

  <label for="note">Note (optional)</label>
  <input type="text" id="note">

  <button type="submit" id="add-expense">Add Expense</button>
  <div class="error" id="form-error"></div>
</form>

<div id="filters">
  <h2>Filters</h2>
  <label for="filter-category">Category</label>
  <select id="filter-category">
    <option value="all">All</option>
    <option value="groceries">Groceries</option>
    <option value="transport">Transport</option>
    <option value="bills">Bills</option>
    <option value="fun">Fun</option>
  </select>

  <label for="filter-from">From Date</label>
  <input type="date" id="filter-from">

  <label for="filter-to">To Date</label>
  <input type="date" id="filter-to">
</div>

<div id="expenses">
  <h2>Expenses</h2>
  <table id="expense-table">
    <thead><tr><th>Amount ($)</th><th>Category</th><th>Date</th><th></th></tr></thead>
    <tbody id="expense-tbody"></tbody>
  </table>
</div>

<div class="summary">
  <h2>Summary</h2>
  <div>Total: $<span id="total">0.00</span></div>
  <div data-cat="groceries" class="cat-total">Groceries: $0.00</div>
  <div data-cat="transport" class="cat-total">Transport: $0.00</div>
  <div data-cat="bills" class="cat-total">Bills: $0.00</div>
  <div data-cat="fun" class="cat-total">Fun: $0.00</div>
</div>

<script>
(() => {
  const STORAGE_KEY = 'expenses';
  let expenses = [];

  // DOM Elements
  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const formError = document.getElementById('form-error');

  const expenseTbody = document.getElementById('expense-tbody');
  const totalSpan = document.getElementById('total');
  const catTotals = Array.from(document.querySelectorAll('.cat-total'));

  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  // Load from localStorage
  function loadExpenses() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) expenses = JSON.parse(data);
  }

  // Save to localStorage
  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // Render all expenses
  function renderExpenses() {
    expenseTbody.innerHTML = '';
    const sorted = [...expenses].sort((a,b)=>new Date(b.date)-new Date(a.date));
    for (const exp of sorted) {
      const tr = document.createElement('tr');
      tr.classList.add('expense');
      tr.dataset.category = exp.category;
      tr.dataset.date = exp.date;

      tr.innerHTML = `
        <td>${exp.amount.toFixed(2)}</td>
        <td>${capitalize(exp.category)}</td>
        <td>${exp.date}</td>
        <td><button class="exp-del">Delete</button></td>
      `;
      expenseTbody.appendChild(tr);
    }
  }

  // Capitalize first letter
  function capitalize(str){return str.charAt(0).toUpperCase()+str.slice(1);}

  // Update totals based on visible rows
  function updateTotals() {
    const rows = Array.from(expenseTbody.querySelectorAll('tr.expense'));
    let total = 0;
    const catSums = {groceries:0, transport:0, bills:0, fun:0};

    for (const row of rows) {
      if (!row.classList.contains('hidden')) {
        const amt = parseFloat(row.cells[0].textContent);
        const cat = row.dataset.category;
        total += amt;
        catSums[cat] += amt;
      }
    }

    totalSpan.textContent = total.toFixed(2);
    for (const div of catTotals) {
      const cat = div.dataset.cat;
      div.textContent = `${capitalize(cat)}: $${catSums[cat].toFixed(2)}`;
    }
  }

  // Apply filters
  function applyFilters() {
    const selectedCat = filterCategory.value;
    const fromDate = filterFrom.value ? new Date(filterFrom.value) : null;
    const toDate = filterTo.value ? new Date(filterTo.value) : null;

    const rows = Array.from(expenseTbody.querySelectorAll('tr.expense'));
    for (const row of rows) {
      let visible = true;
      if (selectedCat !== 'all' && row.dataset.category !== selectedCat) visible = false;
      const expDate = new Date(row.dataset.date);
      if (fromDate && expDate < fromDate) visible = false;
      if (toDate && expDate > toDate) visible = false;
      row.classList.toggle('hidden', !visible);
    }
    updateTotals();
  }

  // Add expense
  form.addEventListener('submit', e=>{
    e.preventDefault();
    const amtVal = amountInput.value.trim();
    const catVal = categorySelect.value;
    const dateVal = dateInput.value;

    if (!amtVal || isNaN(amtVal) || Number(amtVal)<=0 || !dateVal) {
      formError.textContent = 'Please enter a valid positive amount and date.';
      return;
    }
    formError.textContent = '';
    const newExp = {
      amount: parseFloat(parseFloat(amtVal).toFixed(2)),
      category: catVal,
      date: dateVal,
      note: noteInput.value.trim()
    };
    expenses.push(newExp);
    saveExpenses();
    renderExpenses();
    applyFilters();
    amountInput.value = '';
  });

  // Delete expense
  expenseTbody.addEventListener('click', e=>{
    if (e.target.classList.contains('exp-del')) {
      const row = e.target.closest('.expense');
      const idx = Array.from(expenseTbody.children).indexOf(row);
      const sortedIdx = [...expenses].sort((a,b)=>new Date(b.date)-new Date(a.date)).findIndex(e=>e===expenses[idx]);
      expenses.splice(sortedIdx,1);
      saveExpenses();
      renderExpenses();
      applyFilters();
    }
  });

  // Filter events
  filterCategory.addEventListener('change', applyFilters);
  filterFrom.addEventListener('change', applyFilters);
  filterTo.addEventListener('change', applyFilters);

  // Initial load
  loadExpenses();
  renderExpenses();
  applyFilters();
})();
</script>

</body>
</html>
